import LockOutlinedIcon from "@mui/icons-material/LockOutlined";
import { Dialog, DialogActions, DialogContent, DialogTitle, useMediaQuery } from "@mui/material";
import Avatar from "@mui/material/Avatar";
import Box from "@mui/material/Box";
import Button from "@mui/material/Button";
import Container from "@mui/material/Container";
import CssBaseline from "@mui/material/CssBaseline";
import TextField from "@mui/material/TextField";
import Typography from "@mui/material/Typography";
import { useTheme } from '@mui/material/styles';
import { debounce } from "@mui/material/utils";
import { navigate } from "gatsby";
import React, { useState } from "react";
import CustomButton from "../components/CustomButton/CustomButton";
import Layout from "../components/Layout";
import useUser from "../storage/useUser";

export default function Email() {
    const theme = useTheme();
    const isLargeScreen = useMediaQuery(theme.breakpoints.up('lg'));
    const { checkEmail } = useUser();

    const [email, setEmail] = useState<string>("");
    const [openAlert, setOpenAlert] = useState<boolean>(false);

    const handleCheckEmail = async (): Promise<void> => {
        if (email) {
            checkEmail(email)
                .then((res) => {
                    if (res) {
                        setOpenAlert(true)
                    }
                    else {
                        navigate(`/checkout?email=${email}`)
                    }
                })
                .catch((e) => {
                    console.log("e: ", e);
                });
        }
    };


    return (
        <Layout hideFooter={true}>
            <Dialog
                open={openAlert}
                onClose={() => setOpenAlert(false)}
                aria-labelledby="alert-dialog-title"
                aria-describedby="alert-dialog-description"
            >
                <DialogTitle id="alert-dialog-title">
                    {"Para concluir o login, clique no link enviado no seu email"}
                </DialogTitle>
                <DialogContent>

                </DialogContent>
                <DialogActions sx={{ display: 'flex', justifyContent: 'center' }}>
                    <CustomButton title="Ok" onClick={() => console.log('todo')} width="90%" />
                </DialogActions>
            </Dialog>
            <Container>
                <CssBaseline />
                <Box
                    sx={{
                        marginTop: 8,
                        display: "flex",
                        flexDirection: "column",
                        alignItems: "center",
                    }}
                >
                    <Avatar sx={{ m: 1, bgcolor: "secondary.main" }}>
                        <LockOutlinedIcon />
                    </Avatar>
                    <Typography component="h1" variant="h6">
                        Para finalizar a compra, informe seu e-mail.
                    </Typography>
                    <Box width={isLargeScreen ? '50%' : '80%'}>
                        <TextField
                            margin="normal"
                            fullWidth
                            label="Email"
                            name="email"
                            autoComplete="email"
                            onKeyUp={(e) => e.key === "Enter" && handleCheckEmail()}
                            onChange={(e) => setEmail(e.target.value)}
                            autoFocus
                        />

                        <Button
                            fullWidth
                            variant="contained"
                            type="submit"
                            onClick={debounce(handleCheckEmail, 500)}
                            sx={{ mt: 3, mb: 2 }}
                        >
                            Continuar
                        </Button>

                    </Box>
                </Box>
            </Container>
        </Layout>
    );
}
